INSERT IGNORE INTO app_templates (name, slug, description, category, icon, docker_image, docker_command, default_port, requires_domain, requires_repo, environment_variables, created_at) VALUES
('C/C++ App', 'cpp', 'Aplicação compilada em C ou C++. GCC, G++, CMake e Make inclusos.', 'backend', '⚙️', 'gcc:latest', 'sh -c "cd /app && if [ -f CMakeLists.txt ]; then mkdir -p build && cd build && cmake .. && make; elif [ -f Makefile ]; then make; elif ls *.cpp 1>/dev/null 2>&1; then g++ -o app *.cpp -lpthread; elif ls *.c 1>/dev/null 2>&1; then gcc -o app *.c -lpthread; fi && if [ -f build/app ]; then ./build/app; elif [ -f app ]; then ./app; else echo No binary found; fi"', 8080, 0, 1, '{"APP_PORT":"8080","BUILD_TYPE":"release"}', NOW());
